INSERT INTO recipe (title, parts, description, img, id_recipe_subcategory) VALUES
    ('Cake salé lardons & olives',6,'Préchauffer le four à 180°. Découper les olives en 2 et faire cuire les lardons au micro-onde. Dans un saladier, fouetter les œufs, la farine, la levure, le sel et le poivre. Incorporer petit à petit l’huile et le lait préalablement chauffé. Ajouter le gruyère râpé et mélanger. Enfin, incorporer les olives et les lardons. Bien mélanger. Verser le tout dans un moule et faire cuire pendant 40 minutes.','cake_sale.jpg',(SELECT id FROM recipe_subcategory WHERE label = 'Apéritif')),
    ('Cookies salés',4,'Mélanger le beurre et le parmesan. Ajouter la farine, l’huile d’olive, l’œuf et les épices. Pétrir jusqu’à obtenir un mélange homogène. Incorporer les lardons. Former des boules et les faire cuire 15 minutes à 180 degrés.','cookies_sales.jpg',(SELECT id FROM recipe_subcategory WHERE label = 'Apéritif')),
    ('Ktipiti',4,'Faire cuire les poivrons coupés en deux et la gousse d’ail 25 minutes à 200 degrés. Les laisser 20 minutes supplémentaires dans le four éteint pour que la peau se retire facilement. Une fois épluchés et refroidis, les placer dans le blender avec tous les autres ingrédients et mixer. Mettre la préparation au frais au moins 1 heure avant de servir.','ktipiti.jpg',(SELECT id FROM recipe_subcategory WHERE label = 'Apéritif')),
    ('Tarte fine', NULL, 'Couper les tomates cerises en deux et les courgettes en rondelles. Etaler le pesto sur la pâte puis placer les légumes. Parsemer d’herbes de Provence. Enfourner à 180°C pendant 25 minutes.','https://i.ibb.co/mh2grgb/1704036446453.jpg', 2),
    ('Risotto', 2, 'Faire revenir le riz dans un peu d’huile d’olive jusqu’à ce qu’il soit translucide. Ajouter progressivement le bouillon. Faire revenir les oignons et champignons séparément. Ajouter parmesan, champignons et olives à la fin.','https://i.ibb.co/H29ccV4/1704035758811.jpg', 2),
    ('Gaufres de patate douce', NULL, 'Mélanger la purée et les œufs battus. Ajouter farine et levure. Cuire dans le gaufrier. Garnir avec yaourt, citron, ciboulette, saumon fumé et œuf mollet.','https://i.ibb.co/tQ585sN/1704035758830.jpg', 2),
    ('Gaufres de l’espace', 4, 'Mélanger épinards, farine, levure, lait et œuf. Cuire dans le gaufrier.', NULL, 2),
    ('Pancakes de pomme de terre', NULL, 'Faire bouillir les pommes de terre, réduire en purée. Ajouter farine, former des boules avec un cube de fromage au centre. Cuire comme pancakes.','https://i.ibb.co/VVkx7Cf/1704035758836.jpg', 2),
    ('Dahl', 2, 'Faire revenir oignon, ail, carotte et épices. Ajouter lentilles et lait de coco. Mijoter 30 min en rajoutant de l’eau si nécessaire.','https://i.ibb.co/hyqhw3H/P1000354.jpg', 2),
    ('Carottes pesto', 2, 'Cuire les carottes à l’eau puis ajouter le pesto. Servir avec du riz.', NULL, 2),
    ('Omelette St Moret', 2, 'Fouetter les œufs et les cuire en omelette. Tartiner de St Moret et ajouter tomate et oignon frais.','https://i.ibb.co/WsC99NQ/1704036446446.jpg', 2),
    ('Stick de Polenta', 4, 'Faire bouillir l’eau avec le cub or, ajouter la semoule. Refroidir, couper en rectangles et enfourner 2 min à 220°C. Servir avec salade ou ratatouille.', NULL, 2),
    ('Croques à l’ancienne', 2, 'Tartiner le pain de pesto, ajouter tomate et mozzarella. Cuire à la poêle jusqu’à ce que le pain soit croustillant.','https://i.ibb.co/gybFs1k/1704036446460.jpg', 2),
    ('Falafels', 4, 'Mixer pois chiche, ail, oignon, herbes, graines et épices. Former des boules et cuire à la poêle. Servir avec salade ou sauce au yaourt.','https://i.ibb.co/gyhrYfY/P1000607.jpg', 2),
    ('Galette maïs', 2, 'Réduire le maïs en purée, ajouter œufs, farine et fromage râpé. Cuire comme pancakes. Servir avec salade.','https://i.ibb.co/q0w8s7W/P1000605.jpg', 2),
    ('Poutine', 2, 'Couper les pommes de terre en frites et cuire. Ajouter sauce, mozzarella et bacon.', NULL, 2),
    ('Tortilla',2,'Couper les pommes de terre et l’oignon en fines tranches. Mettre une bonne dose d’huile d’olive dans une poêle chaude (remplir le fond). Faire revenir les pommes de terre, l’oignon et la gousse d’ail. Une fois cuit, ajouter les œufs préalablement battus. Quand la tortilla se tient, la retourner pour faire cuire l’autre face à l’aide d’une assiette.',NULL,(SELECT id FROM recipe_subcategory WHERE label = 'Végétarien')),
    ('Galette Quinoa',2,'Faire cuire le quinoa. Emincer l’échalote et la faire cuire. Mélanger le quinoa, l’échalote, la farine, le parmesan, l’œuf et les épices. Bien fouetter. Former les galettes sur une poêle chaude et huilée. Les faire dorer de chaque coté à feu moyen. Servir avec une salade.',NULL,(SELECT id FROM recipe_subcategory WHERE label = 'Végétarien')),
    ('Camembert pané',8,'Couper le camembert en morceaux et les paner. Les faire frire. Servir avec une salade composée.',NULL,(SELECT id FROM recipe_subcategory WHERE label = 'Végétarien')),
    ('Arancini',4,'Placer l’oignon émincé dans l’huile d’olive dans une casserole à feu moyen. Ajouter le riz. Dans une autre casserole placer l’eau avec les cubes or. Cuire le riz comme un risotto. Ajouter le parmesan en fin de cuisson. Débarrasser le riz dans un plat et le placer au moins 2h au frais. Former des boules et les garnir. Tremper les arancinis dans un mélange farine + eau puis dans la chapelure. Faire cuire dans l’huile à 170°C pendant 8/10 minutes.',NULL,(SELECT id FROM recipe_subcategory WHERE label = 'Végétarien')),
    ('Soupe de butternut',4,'Faire revenir l’échalote avec le beurre. Ajouter le butternut en cube. Recouvrir d’eau et assaisonner. Laisser cuire 30 minutes. Mixer la préparation puis ajouter la crème fraîche. Servir avec des lardons, un œuf mollet et du pain grillé.',NULL,(SELECT id FROM recipe_subcategory WHERE label = 'Végétarien')),
    ('Maïs rôti',2,'Préparer la marinade. Déposer les épis de maïs sur une plaque allant au four. Les badigeonner de la marinade. Enfourner à 180 degrés pendant 20 minutes.',NULL,(SELECT id FROM recipe_subcategory WHERE label = 'Végétarien')),
    ('Pâtes aux poivrons',2,'Faire cuire les poivrons avec l’échalote et un peu d’eau. Mixer les poivrons avec le yaourt et le St Moret. Mélanger la sauce aux pâtes et servir surmonté d’une burrata.','https://i.ibb.co/0rzwxtL/P1000363.jpg',(SELECT id FROM recipe_subcategory WHERE label = 'Pâtes')),
    ('Pâtes aux tomates séchées',2,'Faire revenir l’oignon et l’ail avec un peu d’huile des tomates séchées. Ajouter les tomates séchées coupées en lamelles puis la ricotta. Ajuster la texture avec l’eau de cuisson des pâtes. Mélanger la sauce avec les pâtes cuites et servir avec du parmesan.','https://ibb.co/Vc0Y359K',(SELECT id FROM recipe_subcategory WHERE label = 'Pâtes')),
    ('Pâtes à la fêta',2,'Placer les tomates cerises, la fêta et les morceaux de courgettes dans un plat allant au four. Parsemer d’herbes de Provence et arroser d’huile d’olive. Cuire 20 minutes à 200°C. Mélanger avec les pâtes cuites.',NULL,(SELECT id FROM recipe_subcategory WHERE label = 'Pâtes')),
    ('Pâtes au chorizo',2,'Faire revenir les poivrons dans une poêle. Ajouter la sauce tomate, l’eau, le chorizo et les épices. Mélanger avec les pâtes cuites et servir.',NULL,(SELECT id FROM recipe_subcategory WHERE label = 'Pâtes')),
    ('Lasagnes', 4, 'Faire revenir l’oignon dans un peu d’huile d’olive. Une fois translucide, ajouter la viande hachée et la sauce tomate. Faire cuire au moins 10 minutes. Préparer la béchamel en faisant fondre le beurre dans une casserole. Une fois qu’il bout, ajouter la farine hors du feu et mélanger. Remettre sur le feu et incorporer le lait progressivement tout en fouettant énergiquement. Une fois tout le lait incorporé et le mélange épaissi, retirer du feu. Dresser les lasagnes dans un plat rectangulaire allant au four en alternant couche de pâte, préparation à la viande et béchamel. Terminer par une couche de béchamel et parsemer le plat de fromage râpé. Enfourner environ 25 minutes à 180 degrés.', 'lasagnes.jpg', (SELECT id FROM recipe_subcategory WHERE label = 'Viande')),
    ('Chili con carne', 2, 'Émincer l’oignon. Le faire revenir dans une casserole huilée. Ajouter la viande hachée, puis une fois dorée, verser la sauce tomate. Assaisonner à l’aide du Garam Masala, curcuma et paprika, puis terminer en ajoutant le maïs et les haricots rouges. Faire frémir au moins 20 minutes. Servir avec du riz.', 'chili.jpg', (SELECT id FROM recipe_subcategory WHERE label = 'Viande')),
    ('Butter chicken', 2, 'Commencer par faire mariner le poulet avec l’ail, yaourt, citron, Garam Masala, cumin, paprika et gingembre, puis réserver. Dans une poêle, faire cuire l’oignon et l’ail avec les tomates. Ajouter un verre d’eau et les épices. Laisser mijoter 15 minutes. Ajouter le beurre et le poulet. Servir avec du riz.', 'butter_chicken.jpg', (SELECT id FROM recipe_subcategory WHERE label = 'Viande')),
    ('Poulet aux olives', 2, 'Couper le poulet et le mettre dans un bol avec l’oignon râpé, les épices, le persil et l’huile d’olive. Laisser reposer 30 minutes au frais. Faire revenir l’oignon ciselé et l’ail dans une casserole à feu doux. Ajouter le poulet et un peu d’eau. Ajouter les pommes de terre et couvrir d’eau à hauteur. Laisser cuire 40 minutes à couvert. Ajouter les olives et servir.', 'poulet_olives.jpg', (SELECT id FROM recipe_subcategory WHERE label = 'Viande')),
    ('Empanadas', 15, 'Pour la pâte : Mélanger les ingrédients secs (farine, sel et sucre). Ajouter le beurre en cubes et mélanger jusqu’à obtention d’une texture sableuse. Incorporer ensuite l’eau et le jaune d’œuf. Mélanger jusqu’à obtention d’une pâte homogène. Filmer et réserver au frais 1h. Pour la garniture : faire revenir tous les ingrédients dans une poêle. Découper des cercles de pâte, garnir, refermer et dorer. Faire cuire 25 à 30 minutes à 200 degrés.', 'https://ibb.co/vxvkt8Rm', (SELECT id FROM recipe_subcategory WHERE label = 'Viande')),
    ('Bœuf bourguignon', 4, 'Faire fondre le beurre avec l’huile dans une poêle. Faire revenir l’oignon et la carotte coupés en morceaux et saupoudrer de farine. Une fois la farine dorée, verser le vin rouge et un peu d’eau pour déglacer. Dans une cocotte, faire dorer la viande et ajouter la sauce. Couvrir et laisser frémir 2h. Ajouter le bouquet garni et laisser cuire 1h supplémentaire.', 'boeuf_bourguignon.jpg', (SELECT id FROM recipe_subcategory WHERE label = 'Viande')),
    ('Blanquette de veau', 4, 'Faire revenir la viande avec les échalotes dans un peu de beurre. Ajouter le vin blanc, le cub or et 3 verres d’eau. Incorporer les carottes et champignons. Saupoudrer de farine, mélanger et ajouter le bouquet garni. Laisser mijoter 2h à couvert. En fin de cuisson, découvrir et ajouter la crème. Bien mélanger et servir.', 'blanquette.jpg', (SELECT id FROM recipe_subcategory WHERE label = 'Viande')),
    ('Poulet Basquaise', 4, 'Tailler les poivrons et les oignons. Dans une casserole, verser la graisse de canard, les poivrons, les oignons et l’ail. Ajouter les piments doux et la sauce tomate. Assaisonner avec le piment d’Espelette, sel et poivre. Ajouter le poulet doré à part et laisser mijoter 45 minutes. Servir avec du riz.', 'https://ibb.co/mVxcLhFL', (SELECT id FROM recipe_subcategory WHERE label = 'Viande')),
    ('Tourte à la viande', 8, 'Faire revenir l’échalote à la poêle dans un peu d’huile. Ajouter les viandes, carottes et champignons. Hors du feu, ajouter ricotta et persil. Piquer la pâte puis garnir la tourte. Dorer et enfourner 30 minutes à 170 degrés. Servir avec pommes de terre rôties et confit d’oignon.', 'tourte_viande.jpg', (SELECT id FROM recipe_subcategory WHERE label = 'Viande')),
    ('Hachis Parmentier', 4, 'Préparer la purée. Émincer oignons et ail, les faire revenir avec beurre et huile. Ajouter la viande et cuire. Verser le fond de veau et herbes aromatiques. Placer la viande dans un plat, recouvrir de purée et parsemer de chapelure. Gratiner 10 minutes au four.', 'hachis_parmentier.jpg', (SELECT id FROM recipe_subcategory WHERE label = 'Viande')),
    ('Rougail saucisse', 2, 'Faire revenir l’oignon dans un peu d’huile. Ajouter les bouts de saucisses coupées en morceaux puis la sauce tomate. Assaisonner avec des épices et/ou du piment. Laisser mijoter 15 minutes. Servir avec du riz.', 'https://i.ibb.co/98mv7BM/P1000157.jpg', (SELECT id FROM recipe_subcategory WHERE label = 'Viande')),
    ('Saumon teriyaki',2,'Préparer la marinade en mélangeant sauce soja, mirin, cassonade, gingembre et ail. Porter à ébullition puis déposer sur les pavés de saumon et laisser mariner 1h. Cuire avec la marinade et servir avec du riz, parsemer de graines de sésame.',NULL,(SELECT id FROM recipe_subcategory WHERE label = 'Poisson')),
    ('Poisson à la provençale',2,'Placer les filets de poisson dans un plat allant au four. Ajouter les olives et la tomate en rondelles. Parsemer d’herbes de Provence, arroser d’huile d’olive et cuire 20 min à 180°C.',NULL,(SELECT id FROM recipe_subcategory WHERE label = 'Poisson')),
    ('Bûche de saumon',8,'Mélanger le saumon avec du jus de citron et de l’aneth. Mélanger le fromage avec sel et poivre. Dans un moule filmé, alterner saumon fumé, pain de mie, fromage et saumon mariné. Réserver 3h au frais. Décorer d’aneth et de citron.',NULL,(SELECT id FROM recipe_subcategory WHERE label = 'Poisson')),
    ('Fish & chips',4,'Mélanger maïzena, farine, levure, cumin, sucre, sel, poivre et eau gazeuse. Fariner les filets de poisson, les tremper dans la préparation et les frire quelques minutes. Servir avec frites et sauce tartare.','https://i.ibb.co/XLvDQXL/P1000086.jpg',(SELECT id FROM recipe_subcategory WHERE label = 'Poisson')),
    ('Poisson en croûte de chorizo',2,'Mixer le chorizo avec le parmesan. Recouvrir les filets de poisson de la préparation et cuire 30 min à 200°C.',NULL,(SELECT id FROM recipe_subcategory WHERE label = 'Poisson')),
    ('Pizza Québécoise',1,'Mettre la crème fraîche en base. Ajouter le fromage, le bacon, les noix de pécan et les cranberries. Arroser de sirop d’érable avant d’enfourner.',NULL,(SELECT id FROM recipe_subcategory WHERE label='Pizza')),
    ('Sandwich Raclette',1,'Sandwich composé de fromage à raclette, cornichons et jambon de parme.','https://i.ibb.co/cTYds0X/1704035758842.jpg',(SELECT id FROM recipe_subcategory WHERE label = 'Sandwich')),
    ('Sandwich brie / lard',1,'Sandwich composé de brie ou reblochon, lard fumé cuit, oignon frit, épinards frais et sauce tartare.','https://i.ibb.co/WsC99NQ/1704036446446.jpg',(SELECT id FROM recipe_subcategory WHERE label = 'Sandwich')),
    ('Brochettes bœuf fromage', 20, 'Mélanger tous les ingrédients pour préparer la marinade. Découper le fromage en rectangles épais. Les enrouler d’une tranche de carpaccio. Les placer dans une poêle avec la sauce et arroser en cours de cuisson.', 'https://i.ibb.co/PZzkQFz/P1000055.jpg', (SELECT id FROM recipe_subcategory WHERE label = 'Asiatique')),
    ('Banh Bao', 8, 'Préparer la pâte avec les farines, levures, sucre, eau et huile. Laisser lever, former des disques et garnir de farce (viande hachée, champignons, sauces, carotte, cébette, œuf dur). Déposer sur papier sulfurisé et cuire à la vapeur 15 min.', 'https://i.ibb.co/hyqhw3H/P1000354.jpg', (SELECT id FROM recipe_subcategory WHERE label = 'Asiatique')),
    ('Nouilles sautées', 2, 'Cuire les nouilles et les rincer. Faire revenir les légumes dans l’huile de sésame, ajouter la viande puis les nouilles. Terminer avec les sauces.', 'https://i.ibb.co/0rzwxtL/P1000363.jpg', (SELECT id FROM recipe_subcategory WHERE label = 'Asiatique')),
    ('Udon crémeuses', 2, 'Faire revenir ail, oignon, champignons, poivron et brocolis dans un wok. Ajouter sauces, nouilles Udon cuites et crème. Bien mélanger et servir.', 'https://ibb.co/xtNVrwb2', (SELECT id FROM recipe_subcategory WHERE label = 'Asiatique')),
    ('Porc glacé', 2, 'Mariner la poitrine de porc avec sauces, miel, vin chinois et épices. Cuire au four 12 min de chaque côté. Réduire la marinade en sauce et napper le porc.', 'https://ibb.co/hJztJXdD', (SELECT id FROM recipe_subcategory WHERE label = 'Asiatique')),
    ('Pâtes fraiches', 2, 'Former une pâte avec farine et œufs. Filmer et réserver entre 30 min et 1h au frais. Former les pâtes souhaitées, les laisser sécher 30 min puis cuire 3 min dans l’eau bouillante.', 'https://ibb.co/RVRTR96', (SELECT id FROM recipe_subcategory WHERE label = 'Bases salées')),
    ('Pâtes fraiches tomate', 2, 'Former une pâte avec farine, œufs et concentré de tomate. Filmer et réserver entre 30 min et 1h au frais. Former les pâtes, sécher 30 min puis cuire 3 min dans l’eau bouillante.', 'https://ibb.co/Vc0Y359K', (SELECT id FROM recipe_subcategory WHERE label = 'Bases salées')),
    ('Pâtes fraiches épinards', 2, 'Faire cuire les épinards. Mixer avec l’œuf puis mélanger à la farine. Former les pâtes et cuire à l’eau bouillante.', 'https://ibb.co/q0w8s7W/P1000605.jpg', (SELECT id FROM recipe_subcategory WHERE label = 'Bases salées')),
    ('Gnocchis', 4, 'Cuire les pommes de terre puis les réduire en purée. Mélanger avec farine et jaunes d’œufs. Former des petites boules, les marquer à la fourchette et cuire jusqu’à remontée à la surface.', 'gnocchis.jpg', (SELECT id FROM recipe_subcategory WHERE label = 'Bases salées')),
    ('Pâte à tarte healthy', 1, 'Mélanger farine, fromage blanc, huile d’olive et origan. Filmer au contact et réserver au frais au moins 1h. Utiliser pour tartes fines ou mini tartes.', 'https://i.ibb.co/sRdy8d6/1704035758821.jpg', (SELECT id FROM recipe_subcategory WHERE label = 'Bases salées')),
    ('Naans', 4, 'Préparer une pâte avec farine, yaourt, levure, eau et sel. Laisser reposer puis cuire les galettes à la poêle. Variante possible avec garniture (fromage, ail, herbes).', 'naans.jpg', (SELECT id FROM recipe_subcategory WHERE label = 'Bases salées')),
    ('Bretzels', 6, 'Mélanger farine, levure, lait, eau, beurre et sel. Laisser lever 1h30. Former les bretzels, les pocher dans le bicarbonate puis les cuire au four 10 min à 230°C.', 'bretzels.jpg', (SELECT id FROM recipe_subcategory WHERE label = 'Bases salées')),
    ('Kesra', 1, 'Mélanger semoule et huile. Laisser reposer 15 min. Ajouter sel et eau pour obtenir une pâte homogène. Étaler en galette et cuire sur crêpière jusqu’à doré.', 'https://i.ibb.co/1K0g0XL/pate.jpg', (SELECT id FROM recipe_subcategory WHERE label = 'Bases salées')),
    ('Béchamel', 4, 'Faire fondre le beurre dans une casserole. Hors du feu ajouter la farine et fouetter. Remettre sur le feu et ajouter le lait progressivement tout en remuant, jusqu’à épaississement. Assaisonner à sa guise.', 'https://i.ibb.co/1rzSytV/sauce.jpg', (SELECT id FROM recipe_subcategory WHERE label = 'Condiments')),
    ('Sauce échalotes vinaigre', 2, 'Faire revenir les échalotes dans un peu d’huile. Ajouter le vinaigre, l’eau puis le miel. Faire cuire 15-20 min à couvert. Servir avec magret de canard ou bœuf.', 'sauce-echalotes-vinaigre.jpg', (SELECT id FROM recipe_subcategory WHERE label = 'Condiments')),
    ('Sauce aux champignons', 3, 'Faire revenir l’oignon et le beurre, ajouter l’ail et les champignons. Incorporer ketchup, sauces soja, huitre, Hoisin, cub or, vinaigre. Diluer fécule dans eau et ajouter. Cuire 5 min. Servir avec viande et nouilles.', 'sauce-champignons.jpg', (SELECT id FROM recipe_subcategory WHERE label = 'Condiments')),
    ('Pickles', 1, 'Couper les légumes finement. Faire bouillir l’eau. Placer légumes dans le bocal, ajouter eau, vinaigre et sucre. Fermer et réfrigérer au moins une nuit. Déguster le lendemain.', 'pickles.jpg', (SELECT id FROM recipe_subcategory WHERE label = 'Condiments'));
